def parser(log: str) -> dict[str, str]:
    import json
    import re

    results: dict[str, str] = {}
    started: set[str] = set()
    suite_finished = False

    def set_status(name: str, status: str) -> None:
        # Prefer "fail" over anything, and prefer explicit result over earlier ones.
        prev = results.get(name)
        if prev == "fail":
            return
        if status == "fail":
            results[name] = "fail"
            return
        if prev is None:
            results[name] = status
            return
        # pass/skip overwrite nothing unless previous missing
        # but allow skip to overwrite pass if that's what we see last (rare)
        results[name] = status

    def handle_obj(obj: dict) -> None:
        nonlocal suite_finished
        typ = obj.get("type")
        ev = obj.get("event")
        if isinstance(ev, str):
            ev_l = ev.lower()
        else:
            ev_l = None

        if typ == "test":
            name = obj.get("name")
            if not isinstance(name, str) or not name:
                return
            if ev_l == "started":
                started.add(name)
                return
            if ev_l in ("ok", "passed", "pass"):
                set_status(name, "pass")
            elif ev_l in ("failed", "fail", "timeout", "timedout", "error"):
                set_status(name, "fail")
            elif ev_l in ("ignored", "skip", "skipped"):
                set_status(name, "skip")
        elif typ == "suite":
            if ev_l in ("ok", "finished", "ended"):
                suite_finished = True
            elif ev_l in ("failed", "fail"):
                suite_finished = True

    # --- Robust JSON object extraction (works even if JSON spans lines or has prefixes) ---
    buf = []
    depth = 0
    in_str = False
    esc = False
    started_json = False

    def flush_buf():
        nonlocal buf, depth, in_str, esc, started_json
        s = "".join(buf).strip()
        buf = []
        depth = 0
        in_str = False
        esc = False
        started_json = False
        if not s:
            return
        try:
            obj = json.loads(s)
        except Exception:
            return
        if isinstance(obj, dict):
            handle_obj(obj)

    for line in log.splitlines():
        # quick-path: line is JSON
        st = line.lstrip()
        if st.startswith("{") and st.rstrip().endswith("}"):
            try:
                obj = json.loads(st)
            except Exception:
                pass
            else:
                if isinstance(obj, dict):
                    handle_obj(obj)
                    continue

        # scan for JSON objects embedded in text / spanning lines
        for ch in line:
            if not started_json:
                if ch != "{":
                    continue
                started_json = True
                buf = ["{"]
                depth = 1
                in_str = False
                esc = False
                continue

            # already in JSON capture
            buf.append(ch)

            if in_str:
                if esc:
                    esc = False
                elif ch == "\\":
                    esc = True
                elif ch == '"':
                    in_str = False
                continue

            if ch == '"':
                in_str = True
                continue
            if ch == "{":
                depth += 1
            elif ch == "}":
                depth -= 1
                if depth == 0:
                    flush_buf()

        # if JSON spans lines, keep buffer and add newline separator
        if started_json:
            buf.append("\n")

        # --- Fallback: non-JSON rust test harness lines ---
        # e.g. "test foo::bar ... ok" / "test foo ... FAILED" / "test foo ... ignored"
        m = re.match(r"^\s*test\s+(.+?)\s+\.\.\.\s+(ok|FAILED|ignored|skipped)\s*$", line)
        if m:
            name, stt = m.group(1), m.group(2).lower()
            if stt == "ok":
                set_status(name, "pass")
            elif stt in ("ignored", "skipped"):
                set_status(name, "skip")
            else:
                set_status(name, "fail")

    # if we ended while still buffering a JSON object, try flushing (best-effort)
    if started_json:
        flush_buf()

    # If suite finished, any started test lacking a result is a fail (crash/abort)
    if suite_finished:
        for name in started:
            if name not in results:
                results[name] = "fail"

    return results

