def get_pertest_cmd(testcase_list:list[str])->dict[str,str]:
    result: dict[str, str] = {}
    for testcase in testcase_list:
        # Parser names look like libtest full paths, so we can run them as an exact filter.
        result[testcase] = (
            "cd /testbed && "
            "cargo +nightly test -q -p rayon --lib "
            f"'{testcase}' -- --exact --nocapture"
        )
    return result
